<?php
namespace App\Http\Requests;
use Illuminate\Validation\Rule;
class MikrotikDeviceRequest extends TenantAwareRequest { public function authorize(): bool { return true; } public function rules(): array { $device=$this->route('mikrotik'); return ['name'=>['required','string','max:120',Rule::unique('mikrotik_devices','name')->where(fn($q)=>$q->where('tenant_id',$this->tenantId()))->ignore($device?->id)],'site_name'=>['nullable','string','max:120'],'description'=>['nullable','string'],'management_host'=>['required','string','max:255'],'api_port'=>['required','integer','min:1','max:65535'],'api_ssl'=>['nullable','boolean'],'api_username'=>['required','string','max:120'],'api_password'=>[$device ? 'nullable' : 'required','nullable','string','max:255'],'radius_source_ip'=>['required','ip',Rule::unique('mikrotik_devices','radius_source_ip')->ignore($device?->id)],'radius_secret'=>[$device ? 'nullable' : 'required','nullable','string','min:8','max:255'],'coa_port'=>['required','integer','min:1','max:65535'],'hotspot_enabled'=>['nullable','boolean'],'pppoe_enabled'=>['nullable','boolean'],'active'=>['nullable','boolean']]; } }
